641	// OrderedBy returns a Sorter that sorts using the cmp functions, in order.
642	// Call its Sort method to sort the data.
643	func orderedBy(cmp ...cmpFunc) *multiSorter {
644		return &multiSorter{
645			cmp: cmp,
646		}
647	}
