649	// Len is part of sort.Interface.
650	func (ms *multiSorter) Len() int {
651		return len(ms.pods)
652	}
653	
654	// Swap is part of sort.Interface.
655	func (ms *multiSorter) Swap(i, j int) {
656		ms.pods[i], ms.pods[j] = ms.pods[j], ms.pods[i]
657	}
658	
659	// Less is part of sort.Interface.
660	func (ms *multiSorter) Less(i, j int) bool {
661		p1, p2 := ms.pods[i], ms.pods[j]
662		var k int
663		for k = 0; k < len(ms.cmp)-1; k++ {
664			cmpResult := ms.cmp[k](p1, p2)
665			// p1 is less than p2
666			if cmpResult < 0 {
667				return true
668			}
669			// p1 is greater than p2
670			if cmpResult > 0 {
671				return false
672			}
673			// we don't know yet
674		}
675		// the last cmp func is the final decider
676		return ms.cmp[k](p1, p2) < 0
677	}
