692	// exceedMemoryRequests compares whether or not pods' memory usage exceeds their requests
693	func exceedMemoryRequests(stats statsFunc) cmpFunc {
694		return func(p1, p2 *v1.Pod) int {
695			p1Stats, p1Found := stats(p1)
696			p2Stats, p2Found := stats(p2)
697			if !p1Found || !p2Found {
698				// prioritize evicting the pod for which no stats were found
699				return cmpBool(!p1Found, !p2Found)
700			}
701	
702			p1Memory := memoryUsage(p1Stats.Memory)
703			p2Memory := memoryUsage(p2Stats.Memory)
704			p1ExceedsRequests := p1Memory.Cmp(v1resource.GetResourceRequestQuantity(p1, v1.ResourceMemory)) == 1
705			p2ExceedsRequests := p2Memory.Cmp(v1resource.GetResourceRequestQuantity(p2, v1.ResourceMemory)) == 1
706			// prioritize evicting the pod which exceeds its requests
707			return cmpBool(p1ExceedsRequests, p2ExceedsRequests)
708		}
709	}
