568	// ShouldDeleteDuringUpdate is the default function for
569	// checking if an object should be deleted during an update.
570	// It checks if the new object has no finalizers,
571	// the existing object's deletionTimestamp is set, and
572	// the existing object's deletionGracePeriodSeconds is 0 or nil
573	func ShouldDeleteDuringUpdate(ctx context.Context, key string, obj, existing runtime.Object) bool {
574		newMeta, err := meta.Accessor(obj)
575		if err != nil {
576			utilruntime.HandleError(err)
577			return false
578		}
579		oldMeta, err := meta.Accessor(existing)
580		if err != nil {
581			utilruntime.HandleError(err)
582			return false
583		}
584		if len(newMeta.GetFinalizers()) > 0 {
585			// don't delete with finalizers remaining in the new object
586			return false
587		}
588		if oldMeta.GetDeletionTimestamp() == nil {
589			// don't delete if the existing object hasn't had a delete request made
590			return false
591		}
592		// delete if the existing object has no grace period or a grace period of 0
593		return oldMeta.GetDeletionGracePeriodSeconds() == nil || *oldMeta.GetDeletionGracePeriodSeconds() == 0
594	}
